import { useNavigate } from 'react-router-dom';
import { useState, useEffect } from "react";

useEffect(() => {
  fetch("http://localhost:5000/destinations")
    .then(res => res.json())
    .then(data => {
      console.log("API DATA:", data);
      setDestinations(data);
    })
    .catch(err => console.error(err));
}, []);

const categories = [
  { icon: "🏄", label: "Adventure", count: "2,400+" },
  { icon: "👨‍👩‍👧", label: "Family", count: "1,800+" },
  { icon: "💎", label: "Luxury", count: "900+" },
  { icon: "🎒", label: "Backpacker", count: "3,100+" },
  { icon: "🍜", label: "Food & Culture", count: "1,500+" },
  { icon: "🧘", label: "Wellness", count: "700+" },
];

const stats = [
  { value: "180+", label: "Countries" },
  { value: "50k+", label: "Travelers" },
  { value: "12k+", label: "Itineraries" },
  { value: "4.9★", label: "Avg rating" },
];

export default function WanderlyHome() {
  const navigate = useNavigate();
  const [destinations, setDestinations] = useState([]);
  const [activeFilter, setActiveFilter] = useState("All");
  const [searchVal, setSearchVal] = useState("");
  const [scrollY, setScrollY] = useState(0);

  const filters = ["All", "Beach", "Mountains", "City", "Adventure", "Family", "Luxury"];

  useEffect(() => {
    const handleScroll = () => setScrollY(window.scrollY);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <div style={{ fontFamily: "'DM Sans', sans-serif", background: "#0a0f0d", color: "#e8f0ec", minHeight: "100vh", overflowX: "hidden" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:ital,wght@0,300;0,400;0,500;1,300&family=Cormorant+Garamond:ital,wght@0,300;0,400;1,300;1,400&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        ::selection { background: #1D9E75; color: #fff; }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-track { background: #0a0f0d; }
        ::-webkit-scrollbar-thumb { background: #1D9E75; border-radius: 2px; }
        .nav-link { color: rgba(232,240,236,0.55); font-size: 14px; cursor: pointer; transition: color 0.2s; text-decoration: none; }
        .nav-link:hover { color: #e8f0ec; }
        .hero-title { font-family: 'Cormorant Garamond', serif; font-weight: 300; font-style: italic; font-size: clamp(52px, 8vw, 96px); line-height: 1.0; letter-spacing: -0.02em; }
        .hero-subtitle { font-size: 15px; color: rgba(232,240,236,0.55); font-weight: 300; letter-spacing: 0.04em; }
        .search-input { background: transparent; border: none; outline: none; font-family: 'DM Sans', sans-serif; font-size: 15px; color: #e8f0ec; width: 100%; }
        .search-input::placeholder { color: rgba(232,240,236,0.35); }
        .filter-pill { border: 0.5px solid rgba(232,240,236,0.15); border-radius: 20px; padding: 6px 16px; font-size: 13px; cursor: pointer; transition: all 0.2s; background: transparent; color: rgba(232,240,236,0.55); }
        .filter-pill:hover { border-color: rgba(232,240,236,0.4); color: #e8f0ec; }
        .filter-pill.active { background: #1D9E75; border-color: #1D9E75; color: #fff; }
        .dest-card { background: #111a15; border: 0.5px solid rgba(232,240,236,0.08); border-radius: 16px; overflow: hidden; cursor: pointer; transition: transform 0.3s, border-color 0.3s; }
        .dest-card:hover { transform: translateY(-4px); border-color: rgba(29,158,117,0.4); }
        .cat-card { background: #111a15; border: 0.5px solid rgba(232,240,236,0.08); border-radius: 14px; padding: 20px 16px; cursor: pointer; transition: all 0.25s; text-align: center; }
        .cat-card:hover { background: #162219; border-color: rgba(29,158,117,0.35); transform: translateY(-3px); }
        .btn-primary { background: #1D9E75; color: #fff; border: none; border-radius: 10px; padding: 12px 28px; font-size: 15px; font-family: 'DM Sans', sans-serif; cursor: pointer; transition: all 0.2s; letter-spacing: 0.01em; }
        .btn-primary:hover { background: #0F6E56; transform: translateY(-1px); }
        .btn-outline { background: transparent; color: #e8f0ec; border: 0.5px solid rgba(232,240,236,0.25); border-radius: 10px; padding: 12px 28px; font-size: 15px; font-family: 'DM Sans', sans-serif; cursor: pointer; transition: all 0.2s; }
        .btn-outline:hover { border-color: rgba(232,240,236,0.6); }
        .stat-card { background: #111a15; border: 0.5px solid rgba(232,240,236,0.08); border-radius: 14px; padding: 20px 24px; text-align: center; }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(24px); } to { opacity: 1; transform: translateY(0); } }
        .fade-up { opacity: 0; animation: fadeUp 0.7s ease forwards; }
        .fade-up-1 { animation-delay: 0.1s; }
        .fade-up-2 { animation-delay: 0.25s; }
        .fade-up-3 { animation-delay: 0.4s; }
        .fade-up-4 { animation-delay: 0.55s; }
        .fade-up-5 { animation-delay: 0.7s; }
        .glow-dot { width: 6px; height: 6px; border-radius: 50%; background: #1D9E75; display: inline-block; box-shadow: 0 0 8px #1D9E75; }
      `}</style>

      {/* Navbar */}
      <nav style={{ position: "fixed", top: 0, left: 0, right: 0, zIndex: 100, padding: "0 40px", height: 60, display: "flex", alignItems: "center", justifyContent: "space-between", background: scrollY > 40 ? "rgba(10,15,13,0.92)" : "transparent", backdropFilter: scrollY > 40 ? "blur(12px)" : "none", borderBottom: scrollY > 40 ? "0.5px solid rgba(232,240,236,0.08)" : "none", transition: "all 0.3s" }}>
        <div onClick={() => navigate('/')} style={{ cursor: "pointer", display: "flex", alignItems: "center", gap: 8 }}>
          <span className="glow-dot" />
          <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 22, fontStyle: "italic", fontWeight: 400, letterSpacing: "0.02em" }}>Wanderly</span>
        </div>
        <div style={{ display: "flex", gap: 32, alignItems: "center" }}>
          <span className="nav-link" onClick={() => navigate('/')}>Discover</span>
          <span className="nav-link" onClick={() => navigate('/trips/1/plan')}>Plan</span>
          <span className="nav-link" onClick={() => navigate('/search')}>Explore</span>
          <span className="nav-link" onClick={() => navigate('/search')}>Community</span>
        </div>
        <div style={{ display: "flex", gap: 10 }}>
          <button className="btn-outline" style={{ padding: "7px 18px", fontSize: 13 }} onClick={() => navigate('/search')}>Sign in</button>
          <button className="btn-primary" style={{ padding: "7px 18px", fontSize: 13 }} onClick={() => navigate('/search')}>Get started</button>
        </div>
      </nav>

      {/* Hero */}
      <section style={{ minHeight: "100vh", display: "flex", flexDirection: "column", justifyContent: "center", padding: "100px 40px 60px", position: "relative", overflow: "hidden" }}>
        <div style={{ position: "absolute", top: "15%", right: "8%", width: 480, height: 480, borderRadius: "50%", background: "radial-gradient(circle, rgba(29,158,117,0.12) 0%, transparent 70%)", pointerEvents: "none" }} />
        <div style={{ position: "absolute", bottom: "10%", left: "5%", width: 320, height: 320, borderRadius: "50%", background: "radial-gradient(circle, rgba(29,158,117,0.07) 0%, transparent 70%)", pointerEvents: "none" }} />

        <div style={{ maxWidth: 900, position: "relative" }}>
          <div className="fade-up fade-up-1" style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 24 }}>
            <span className="glow-dot" />
            <span style={{ fontSize: 12, letterSpacing: "0.12em", color: "#1D9E75", fontWeight: 500 }}>YOUR WORLD AWAITS</span>
          </div>
          <h1 className="hero-title fade-up fade-up-2">
            Travel the world,<br />
            <span style={{ color: "#1D9E75" }}>your way.</span>
          </h1>
          <p className="hero-subtitle fade-up fade-up-3" style={{ marginTop: 24, maxWidth: 480, lineHeight: 1.7 }}>
            Plan unforgettable trips, discover hidden gems, and connect with a global community of explorers.
          </p>

          {/* Search bar */}
          <div className="fade-up fade-up-4" style={{ marginTop: 40, background: "#111a15", border: "0.5px solid rgba(232,240,236,0.12)", borderRadius: 14, padding: "10px 10px 10px 20px", display: "flex", alignItems: "center", gap: 12, maxWidth: 580 }}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="rgba(232,240,236,0.4)" strokeWidth="2"><circle cx="11" cy="11" r="8"/><path d="M21 21l-4.35-4.35"/></svg>
            <input className="search-input" value={searchVal} onChange={e => setSearchVal(e.target.value)} placeholder="Where do you want to go?" />
            <button className="btn-primary" style={{ padding: "9px 20px", fontSize: 14, whiteSpace: "nowrap" }} onClick={() => navigate('/search')}>
              Explore now
            </button>
          </div>

          {/* Filter pills */}
          <div className="fade-up fade-up-5" style={{ display: "flex", gap: 8, marginTop: 16, flexWrap: "wrap" }}>
            {filters.map(f => (
              <button key={f} className={`filter-pill${activeFilter === f ? " active" : ""}`} onClick={() => { setActiveFilter(f); navigate('/search'); }}>
                {f}
              </button>
            ))}
          </div>
        </div>

        {/* Floating destination cards */}
        <div style={{ position: "absolute", right: 40, top: "50%", transform: "translateY(-50%)", display: "flex", flexDirection: "column", gap: 10, opacity: 0.85 }}>
          {destinations.slice(0, 3).map((d, i) => (
            <div key={d.name} onClick={() => navigate('/destination/' + d.name.toLowerCase())} style={{ background: d.bg, border: `0.5px solid ${d.color}22`, borderRadius: 12, padding: "10px 14px", display: "flex", alignItems: "center", gap: 10, animation: `fadeUp 0.6s ease ${0.6 + i * 0.15}s forwards`, opacity: 0, minWidth: 180, cursor: "pointer" }}>
              <span style={{ fontSize: 22 }}>{d.emoji}</span>
              <div>
                <div style={{ fontSize: 13, fontWeight: 500, color: "#e8f0ec" }}>{d.name}</div>
                <div style={{ fontSize: 11, color: d.color, marginTop: 1 }}>{d.tag}</div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Stats */}
      <section style={{ padding: "0 40px 80px" }}>
        <div style={{ maxWidth: 900, margin: "0 auto", display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 14 }}>
          {stats.map(s => (
            <div key={s.label} className="stat-card">
              <div style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 36, fontWeight: 300, color: "#1D9E75" }}>{s.value}</div>
              <div style={{ fontSize: 13, color: "rgba(232,240,236,0.5)", marginTop: 4 }}>{s.label}</div>
            </div>
          ))}
        </div>
      </section>

      {/* Trending Destinations */}
      <section style={{ padding: "0 40px 80px" }}>
        <div style={{ maxWidth: 900, margin: "0 auto" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 24 }}>
            <div>
              <div style={{ fontSize: 12, letterSpacing: "0.1em", color: "#1D9E75", marginBottom: 6 }}>EXPLORE</div>
              <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 32, fontWeight: 300, fontStyle: "italic" }}>Trending destinations</h2>
            </div>
            <span className="nav-link" style={{ fontSize: 13, color: "#1D9E75" }} onClick={() => navigate('/search')}>View all →</span>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 14 }}>
            {destinations.map((d, i) => (
              <div key={d.name} className="dest-card" onClick={() => navigate('/destination/' + d.name.toLowerCase())}>
                <div style={{ height: 120, background: d.bg, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 48, position: "relative" }}>
                  {d.emoji}
                  <span style={{ position: "absolute", top: 10, right: 10, background: `${d.color}22`, border: `0.5px solid ${d.color}44`, borderRadius: 20, padding: "3px 10px", fontSize: 11, color: d.color }}>{d.tag}</span>
                </div>
                <div style={{ padding: "14px 16px 16px" }}>
                  <div style={{ fontSize: 16, fontWeight: 500 }}>{d.name}</div>
                  <div style={{ fontSize: 13, color: "rgba(232,240,236,0.45)", marginTop: 2 }}>{d.country}</div>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 12 }}>
                    <span style={{ fontSize: 12, color: "rgba(232,240,236,0.35)" }}>⭐ 4.{8 + (i % 2)} · {(8 + i)}k planned</span>
                    <span style={{ fontSize: 12, color: "#1D9E75" }}>Explore →</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Categories */}
      <section style={{ padding: "0 40px 80px" }}>
        <div style={{ maxWidth: 900, margin: "0 auto" }}>
          <div style={{ marginBottom: 24 }}>
            <div style={{ fontSize: 12, letterSpacing: "0.1em", color: "#1D9E75", marginBottom: 6 }}>BROWSE BY</div>
            <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 32, fontWeight: 300, fontStyle: "italic" }}>Travel your style</h2>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(6, 1fr)", gap: 12 }}>
            {categories.map(c => (
              <div key={c.label} className="cat-card" onClick={() => navigate('/search')}>
                <div style={{ fontSize: 28, marginBottom: 10 }}>{c.icon}</div>
                <div style={{ fontSize: 13, fontWeight: 500, color: "#e8f0ec" }}>{c.label}</div>
                <div style={{ fontSize: 11, color: "rgba(232,240,236,0.4)", marginTop: 4 }}>{c.count} spots</div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <section style={{ padding: "0 40px 100px" }}>
        <div style={{ maxWidth: 900, margin: "0 auto", background: "#111a15", border: "0.5px solid rgba(29,158,117,0.2)", borderRadius: 20, padding: "56px 48px", textAlign: "center", position: "relative", overflow: "hidden" }}>
          <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", width: 500, height: 300, borderRadius: "50%", background: "radial-gradient(circle, rgba(29,158,117,0.08) 0%, transparent 70%)", pointerEvents: "none" }} />
          <div style={{ fontSize: 12, letterSpacing: "0.1em", color: "#1D9E75", marginBottom: 16 }}>START FOR FREE</div>
          <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 42, fontWeight: 300, fontStyle: "italic", marginBottom: 16 }}>Ready to explore?</h2>
          <p style={{ fontSize: 15, color: "rgba(232,240,236,0.5)", maxWidth: 400, margin: "0 auto 32px" }}>
            Join 50,000+ travelers who plan smarter and travel better with Wanderly.
          </p>
          <div style={{ display: "flex", gap: 12, justifyContent: "center" }}>
            <button className="btn-primary" style={{ padding: "13px 32px", fontSize: 15 }} onClick={() => navigate('/search')}>Create free account</button>
            <button className="btn-outline" style={{ padding: "13px 32px", fontSize: 15 }} onClick={() => navigate('/search')}>See how it works</button>
          </div>
        </div>
      </section>

      {/* Footer */}
      <footer style={{ borderTop: "0.5px solid rgba(232,240,236,0.08)", padding: "32px 40px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <div onClick={() => navigate('/')} style={{ cursor: "pointer", display: "flex", alignItems: "center", gap: 8 }}>
          <span className="glow-dot" />
          <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 18, fontStyle: "italic" }}>Wanderly</span>
        </div>
        <div style={{ fontSize: 13, color: "rgba(232,240,236,0.3)" }}>© 2026 Wanderly. All rights reserved.</div>
        <div style={{ display: "flex", gap: 24 }}>
          {["Privacy", "Terms", "Contact"].map(l => (
            <span key={l} className="nav-link" style={{ fontSize: 13 }}>{l}</span>
          ))}
        </div>
      </footer>
    </div>
  );
}
